// Test 5: Buttons and links are disabled during formatting
test('FRG-217 / 5. Sample links are disabled while formatting is in progress', async ({ page }) => {
  // Intercept and delay the API for 10 seconds — enough time to verify the disabled state
  await page.route('**/api/format', async route => {
    await new Promise(r => setTimeout(r, 10_000));
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({ xml: MOCK_RESUME_XML, divergence: 0.01, documentType: 'resume' }),
    });
  });

  await gotoAndWait(page);

  // Use the action bar Resume sample link to trigger formatting
  const resumeLink = page.locator('button.sample-link').filter({ hasText: /^Resume$/ });
  await expect(resumeLink).toBeVisible();
  await resumeLink.click();

  // While the API request is in flight, sample links in action bar should be disabled
  const letterLink = page.locator('button.sample-link').filter({ hasText: /^Letter$/ });

  await expect(resumeLink, 'Resume sample link should be disabled during formatting').toBeDisabled({
    timeout: 5_000,
  });
  await expect(letterLink, 'Letter sample link should be disabled during formatting').toBeDisabled({
    timeout: 5_000,
  });
});

